/// Library screen showing all fractals with category filters and search.
/// Similar to catalog but without the featured/hero section.
class FractalLibraryScreen extends StatefulWidget {
  final CatalogRepository catalog;
  final void Function(CatalogEntry entry) onEntryTap;

  const FractalLibraryScreen({
    super.key,
    required this.catalog,
    required this.onEntryTap,
  });

  @override
  State<FractalLibraryScreen> createState() => _FractalLibraryScreenState();
}

enum _LibrarySortOrder { byName, alphabetical }

class _FractalLibraryScreenState extends State<FractalLibraryScreen> {
  String? _selectedCategory;
  bool _showSearch = false;
  _LibrarySortOrder _sortOrder = _LibrarySortOrder.byName;
  final _searchController = TextEditingController();
  final _focusNode = FocusNode();

  // All categories from catalog
  List<String> get _categories {
    final cats = widget.catalog.entries.map((e) => e.category).toSet().toList();
    cats.sort();
    return cats;
  }

  // Filtered entries
  List<CatalogEntry> _filteredEntries(AppLocalizations l10n) {
    final query = _searchController.text.toLowerCase();
    var entries = widget.catalog.entries.toList();

    // Filter by category
    if (_selectedCategory != null) {
      entries = entries.where((e) => e.category == _selectedCategory).toList();
    }

    // Filter by search
    if (query.isNotEmpty) {
      entries = entries.where((e) {
        final name = e.module.displayName(l10n);
        return name.toLowerCase().contains(query) ||
            e.category.toLowerCase().contains(query) ||
            e.catalogId.toLowerCase().contains(query);
      }).toList();
    }

    // Sort
    if (_sortOrder == _LibrarySortOrder.alphabetical) {
      entries.sort((a, b) =>
          a.module.displayName(l10n).compareTo(b.module.displayName(l10n)));
    } else {
      entries.sort((a, b) {
        final cat = a.category.compareTo(b.category);
        if (cat != 0) return cat;
        return a.module.displayName(l10n).compareTo(b.module.displayName(l10n));
      });
    }

    return entries;
  }

  @override
  void dispose() {
    _searchController.dispose();
    _focusNode.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;
    final categories = _categories;
    final entries = _filteredEntries(l10n);

    return Column(
      children: [
        // Category chips row with counts
        Padding(
          padding: const EdgeInsets.symmetric(
              horizontal: AppSpacing.lg, vertical: AppSpacing.sm),
          child: SizedBox(
            height: 40,
            child: ListView.separated(
              scrollDirection: Axis.horizontal,
              itemCount: categories.length + 1,
              separatorBuilder: (_, __) => const SizedBox(width: AppSpacing.xs),
              itemBuilder: (context, index) {
                if (index == 0) {
                  final count = widget.catalog.entries.length;
                  return _LibraryChip(
                    label: 'All',
                    count: count,
                    isSelected: _selectedCategory == null,
                    onTap: () => setState(() => _selectedCategory = null),
                  );
                }
                final category = categories[index - 1];
                final count = widget.catalog.entries
                    .where((e) => e.category == category)
                    .length;
                return _LibraryChip(
                  label: category,
                  count: count,
                  isSelected: _selectedCategory == category,
                  onTap: () => setState(() {
                    _selectedCategory =
                        _selectedCategory == category ? null : category;
                  }),
                );
              },
            ),
          ),
        ),
        // Search field (when visible)
        if (_showSearch)
          Padding(
            padding: const EdgeInsets.fromLTRB(
              AppSpacing.lg,
              AppSpacing.xs,
              AppSpacing.lg,
              AppSpacing.sm,
            ),
            child: TextField(
              controller: _searchController,
              focusNode: _focusNode,
              autofocus: true,
              decoration: InputDecoration(
                hintText: 'Search fractals...',
                prefixIcon: const Icon(Icons.search_rounded),
                suffixIcon: IconButton(
                  icon: const Icon(Icons.close_rounded),
                  onPressed: () {
                    _searchController.clear();
                    setState(() => _showSearch = false);
                    _focusNode.unfocus();
                  },
                ),
                contentPadding:
                    const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
              ),
              onChanged: (_) => setState(() {}),
            ),
          ),
        // Results count
        Padding(
          padding: const EdgeInsets.fromLTRB(
            AppSpacing.lg,
            AppSpacing.xs,
            AppSpacing.lg,
            AppSpacing.sm,
          ),
          child: Row(
            children: [
              Text(
                '${entries.length} results',
                style: AppTypography.labelSmall.copyWith(
                  color: AppColors.textMuted,
                ),
              ),
              const Spacer(),
              // Search button
              IconButton(
                icon: Icon(
                  _showSearch ? Icons.search_off_rounded : Icons.search_rounded,
                  size: 20,
                ),
                onPressed: () {
                  setState(() {
                    _showSearch = !_showSearch;
                    if (_showSearch) {
                      _focusNode.requestFocus();
                    } else {
                      _searchController.clear();
                      _focusNode.unfocus();
                    }
                  });
                },
              ),
              const SizedBox(width: AppSpacing.xs),
              // Sort dropdown
              PopupMenuButton<_LibrarySortOrder>(
                tooltip: l10n.catalogFilterSortOrder,
                initialValue: _sortOrder,
                onSelected: (value) => setState(() => _sortOrder = value),
                itemBuilder: (_) => [
                  PopupMenuItem(
                    value: _LibrarySortOrder.byName,
                    child: Text(l10n.catalogSortByCategory),
                  ),
                  PopupMenuItem(
                    value: _LibrarySortOrder.alphabetical,
                    child: Text(l10n.catalogSortAlphabetical),
                  ),
                ],
                child: ConstrainedBox(
                  constraints:
                      const BoxConstraints(minHeight: 48, minWidth: 48),
                  child: Icon(
                    Icons.sort_rounded,
                    size: 22,
                    color: AppColors.textSecondary,
                  ),
                ),
              ),
            ],
          ),
        ),
        // Fractal list
        Expanded(
          child: entries.isEmpty
              ? Center(
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(
                        Icons.search_off_rounded,
                        size: 48,
                        color: AppColors.textMuted,
                      ),
                      const SizedBox(height: AppSpacing.sm),
                      Text(
                        'No fractals found',
                        style: AppTypography.bodyMedium.copyWith(
                          color: AppColors.textMuted,
                        ),
                      ),
                    ],
                  ),
                )
              : ListView.builder(
                  padding:
                      const EdgeInsets.symmetric(horizontal: AppSpacing.lg),
                  itemCount: entries.length,
                  itemBuilder: (context, index) {
                    final entry = entries[index];
                    return _LibraryCard(
                      entry: entry,
                      onTap: () => widget.onEntryTap(entry),
                      l10n: l10n,
                    );
                  },
                ),
        ),
      ],
    );
  }
