                            ),
                          ),
                        ],
                      ),
                    ),
                    AnimatedContainer(
                      duration: AppAnimations.fast,
                      padding: const EdgeInsets.all(8),
                      decoration: BoxDecoration(
                        color: _isPressed
                            ? AppColors.primary.withValues(alpha: 0.2)
                            : AppColors.surfaceVariant,
                        borderRadius: BorderRadius.circular(10),
                      ),
                      child: Icon(
